357→    private fun getEditorHook(): EditPostActivityHook {
358→        val activity = activity
359→        return if (activity is EditPostActivityHook) {
360→            activity
361→        } else {
362→            throw RuntimeException("$activity must implement EditPostActivityHook")
363→        }
364→    }
